type ExpiryRecord = {
  expiryDate?: string | Date | null
}

const MS_PER_DAY = 24 * 60 * 60 * 1000

const toDateParts = (value?: string | Date | null) => {
  if (!value) return null

  if (value instanceof Date) {
    if (Number.isNaN(value.getTime())) return null
    return { year: value.getFullYear(), month: value.getMonth() + 1, day: value.getDate() }
  }

  if (typeof value === 'string') {
    const match = value.match(/(\d{4})-(\d{2})-(\d{2})/)
    if (match) {
      const year = Number(match[1])
      const month = Number(match[2])
      const day = Number(match[3])
      if (year && month && day) {
        return { year, month, day }
      }
    }

    const parsed = new Date(value)
    if (!Number.isNaN(parsed.getTime())) {
      return { year: parsed.getFullYear(), month: parsed.getMonth() + 1, day: parsed.getDate() }
    }
  }

  return null
}

const toUtcMidnight = (parts: { year: number; month: number; day: number }) =>
  Date.UTC(parts.year, parts.month - 1, parts.day)

export const getDaysUntilExpiry = (expiryDate?: string | Date | null, referenceDate: Date = new Date()) => {
  const expiryParts = toDateParts(expiryDate)
  const referenceParts = toDateParts(referenceDate)
  if (!expiryParts || !referenceParts) return null
  return Math.round((toUtcMidnight(expiryParts) - toUtcMidnight(referenceParts)) / MS_PER_DAY)
}

export const isExpiredItem = (item: ExpiryRecord, referenceDate?: Date) => {
  const daysLeft = getDaysUntilExpiry(item.expiryDate, referenceDate || new Date())
  return typeof daysLeft === 'number' && daysLeft < 0
}

export const isExpiringSoonItem = (item: ExpiryRecord, thresholdDays: number = 5, referenceDate?: Date) => {
  const daysLeft = getDaysUntilExpiry(item.expiryDate, referenceDate || new Date())
  return typeof daysLeft === 'number' && daysLeft >= 0 && daysLeft <= thresholdDays
}

export const getExpiredItems = <T extends ExpiryRecord>(items: T[], referenceDate?: Date) =>
  items.filter(item => isExpiredItem(item, referenceDate))

export const getExpiringSoonItems = <T extends ExpiryRecord>(items: T[], thresholdDays: number = 5, referenceDate?: Date) =>
  items.filter(item => isExpiringSoonItem(item, thresholdDays, referenceDate))
